where t.del_flag = '0'
AND t.task_title like concat('%', #{taskTitle}, '%')
AND t.publish_user_id = #{publishUserId}
AND t.receive_user_id = #{receiveUserId}
AND t.priority = #{priority}
AND t.task_status = #{taskStatus}

    AND date_format(t.create_time,'%Y%m%d') >= date_format(#{params.beginTime},'%Y%m%d')


